{{
  (() => {
    const raw = String($fromAI('search_term', 'Nome, telefone, email ou id da pessoa/lead que deve ser pesquisado', 'string') || '').trim();
    if (!raw) {
      return "SELECT 'search_term obrigatorio' AS error;";
    }

    const term = raw.replace(/'/g, "''");
    const digits = raw.replace(/\D/g, '');
    const phoneCondition = digits ? ` OR COALESCE(p.primary_phone, '') ILIKE '%${digits}%'` : '';

    return `
WITH matched_people AS (
  SELECT p.*
  FROM public.people p
  WHERE
    p.id::text = '${term}'
    OR p.full_name ILIKE '%${term}%'
    OR COALESCE(p.email, '') ILIKE '%${term}%'
    ${phoneCondition}
    OR COALESCE(p.last_interaction_preview, '') ILIKE '%${term}%'
  ORDER BY
    CASE
      WHEN p.id::text = '${term}' THEN 0
      WHEN COALESCE(p.email, '') ILIKE '${term}' THEN 1
      WHEN COALESCE(p.full_name, '') ILIKE '${term}' THEN 2
      ELSE 3
    END,
    p.updated_at DESC
  LIMIT 10
)
SELECT
  p.id,
  p.full_name,
  p.primary_phone,
  p.email,
  p.crm_status,
  p.crm_score,
  p.crm_unread,
  p.origin,
  p.tags,
  p.last_interaction_preview,
  COALESCE(p.metadata->>'latest_real_estate_intent', p.metadata->'lead_profile'->>'intent') AS intent,
  p.metadata->'lead_profile' AS lead_profile,
  COALESCE((
    SELECT jsonb_agg(note->>'content')
    FROM jsonb_array_elements(COALESCE(p.metadata->'lead_notes', '[]'::jsonb)) AS note
    WHERE COALESCE(note->>'visibility', '') = 'ai'
  ), '[]'::jsonb) AS notes_ai,
  (
    SELECT COUNT(*)
    FROM public.person_properties pp
    WHERE pp.person_id = p.id
  ) AS linked_properties_count,
  p.updated_at
FROM matched_people p
ORDER BY p.updated_at DESC;
    `;
  })()
}}

